function syninfo(cas, syn, rank, source){
  this.cas = cas;
  this.syn = syn;
  this.rank = rank;
  this.source = source;
}

function exactSyn(syn){
  var uSyn = syn.toUpperCase();
  var results = new Array();
  for(var i=0;i<syns.length;i++){
    var s = syns[i];
    if (s.syn.toUpperCase() == uSyn){
      results.push(i);
    }
  }
  return results;
}

function beginSyn(syn){
  var uSyn = syn.toUpperCase();
  var results = new Array();
  for(var i=0;i<syns.length;i++){
    var s = syns[i];
    var ssu = s.syn.toUpperCase();
    if (ssu.startsWith(uSyn)){
      results.push(i);
    }
  }
  return results;
}

function containsSyn(syn){
  var uSyn = syn.toUpperCase();
  var results = new Array();
  for(var i=0;i<syns.length;i++){
    var s = syns[i];
    var ssu = s.syn.toUpperCase();
    if (ssu != ""){
      if (ssu.indexOf(uSyn) > -1){
        results.push(i);
      }
    }
  }
  return results;
}


